97: class FilterConfig {
98:   using LabelsMap = Protobuf::Map<std::string, std::string>;
99: 
100: public:
101:   FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
102:                Stats::Scope& scope, const std::string& stats_prefix,
103:                Server::Configuration::ServerFactoryContext& factory_context);
104: 
