118: 
119:   bool headersAsBytes() const { return encode_raw_headers_; }
120: 
121:   Filters::Common::MutationRules::CheckResult
122:   checkDecoderHeaderMutation(const Filters::Common::MutationRules::CheckOperation& operation,
123:                              const Http::LowerCaseString& key, absl::string_view value) const {
124:     if (!decoder_header_mutation_checker_.has_value()) {
125:       return Filters::Common::MutationRules::CheckResult::OK;
126:     }
127:     return decoder_header_mutation_checker_->check(operation, key, value);
128:   }
129: 
130:   // Used for headers_to_remove to avoid a redundant pseudo header check.
131:   bool hasDecoderHeaderMutationRules() const {
132:     return decoder_header_mutation_checker_.has_value();
133:   }
134: 
135:   bool enableDynamicMetadataIngestion() const { return enable_dynamic_metadata_ingestion_; }
136: 
137:   Http::Code statusOnError() const { return status_on_error_; }
138: 
139:   bool validateMutations() const { return validate_mutations_; }
140: 
141:   bool filterEnabled(const envoy::config::core::v3::Metadata& metadata) {
142:     const bool enabled = filter_enabled_.has_value() ? filter_enabled_->enabled() : true;
143:     const bool enabled_metadata =
144:         filter_enabled_metadata_.has_value() ? filter_enabled_metadata_->match(metadata) : true;
145:     return enabled && enabled_metadata;
146:   }
