196: private:
197:   static Http::Code toErrorCode(uint64_t status) {
198:     const auto code = static_cast<Http::Code>(status);
199:     if (code >= Http::Code::Continue && code <= Http::Code::NetworkAuthenticationRequired) {
200:       return code;
201:     }
202:     return Http::Code::Forbidden;
203:   }
