205:   ExtAuthzFilterStats generateStats(const std::string& prefix,
206:                                     const std::string& filter_stats_prefix, Stats::Scope& scope) {
207:     const std::string final_prefix = absl::StrCat(prefix, "ext_authz.", filter_stats_prefix);
208:     return {ALL_EXT_AUTHZ_FILTER_STATS(POOL_COUNTER_PREFIX(scope, final_prefix))};
209:   }
